class Solution:
    def minOperations(self, k: int) -> int:
        import math
        if k == 1:
            return 0
        best = float('inf')
        for v in range(1, k + 1):
            copies = math.ceil(k / v)
            cost = (v - 1) + max(0, copies - 1)
            best = min(best, cost)
            if v >= k:
                break
        return best

