var minOperations = function(k) {
    if (k === 1) return 0;
    let best = Infinity;
    for (let v = 1; v <= k; v++) {
        const copies = Math.ceil(k / v);
        const cost = (v - 1) + Math.max(0, copies - 1);
        best = Math.min(best, cost);
    }
    return best;
};
